void findK(long height, knode *knodes, long knodes_elem, long *currKnode, long *offset, int *keys, record *records, record *ans, int count, int order) {
	#pragma omp parallel for schedule(static)
	for (int bid = 0; bid < count; bid++) {
		// Simulate the traversal for each query `bid`.
		// The original CUDA kernel used `bid` as block index and `thid` as thread index within the block.
		// In OpenMP, we parallelize over `bid` (the query index).
		// The `thid` logic in CUDA was for searching within a node.
		// Here, we simulate that search sequentially for each `bid`.

		long current_node_idx = currKnode[bid];
		long next_node_idx = offset[bid]; // Initialize with the starting offset for this query

		for (int i = 0; i < height; i++) {
			// Find the correct child pointer for the current key `keys[bid]`
			int found_child_idx = -1;
			// Iterate through the keys of the current node to find the correct child.
			// The CUDA kernel used `thid` and `thid+1` to compare.
			// Here, we iterate from 0 up to `knodes[current_node_idx].num_keys`.
			// The condition `knodesD[currKnodeD[bid]].keys[thid] <= keysD[bid] && knodesD[currKnodeD[bid]].keys[thid+1] > keysD[bid]`
			// implies that `thid` goes up to `order - 1` (or `threadsPerBlock - 1`).
			// We need to find the index `j` such that `knodes[current_node_idx].keys[j] <= keys[bid]` and `knodes[current_node_idx].keys[j+1] > keys[bid]`.
			// If `keys[bid]` is smaller than the first key, `j` would be -1 conceptually.
			// If `keys[bid]` is larger than or equal to the last key, `j` would be `num_keys - 1`.

			int num_keys_in_node = knodes[current_node_idx].num_keys;
			int search_key = keys[bid];

			// Find the index `j` such that keys[j] <= search_key < keys[j+1]
			// If search_key < keys[0], then j = -1 (conceptually, points to the first child)
			// If search_key >= keys[num_keys-1], then j = num_keys - 1 (points to the last child)
			int j = -1;
			for (int k = 0; k < num_keys_in_node; k++) {
				if (knodes[current_node_idx].keys[k] <= search_key) {
					j = k;
				} else {
					break; // Keys are sorted
				}
			}

			// The child index is `j + 1` if `j` is a valid index for a key, or `0` if `search_key` is smaller than all keys.
			// In the CUDA kernel: `knodesD[offsetD[bid]] = knodesD[currKnodeD[bid]].indices[thid];`
			// This means `offsetD[bid]` is updated with the index of the child node.
			// The `thid` in CUDA corresponds to the index `j` found above.
			// So, `offset[bid]` should be updated with `knodes[current_node_idx].indices[j]`.

			if (j >= 0 && j < num_keys_in_node) {
				// If search_key is between keys[j] and keys[j+1]
				if (knodes[current_node_idx].keys[j] <= search_key && (j + 1 >= num_keys_in_node || knodes[current_node_idx].keys[j + 1] > search_key)) {
					next_node_idx = knodes[current_node_idx].indices[j];
				} else if (search_key >= knodes[current_node_idx].keys[num_keys_in_node - 1]) {
					// If search_key is greater than or equal to the last key
					next_node_idx = knodes[current_node_idx].indices[num_keys_in_node - 1];
				} else {
					// This case should ideally not be reached if logic is correct, but for safety:
					// If search_key is less than the first key
					next_node_idx = knodes[current_node_idx].indices[0];
				}
			} else if (search_key < knodes[current_node_idx].keys[0]) {
				// If search_key is smaller than all keys in the node
				next_node_idx = knodes[current_node_idx].indices[0];
			} else {
				// If search_key is greater than or equal to the last key
				next_node_idx = knodes[current_node_idx].indices[num_keys_in_node - 1];
			}

			// The CUDA kernel had `if(knodesD[offsetD[bid]].indices[thid] < knodes_elem)`
			// This check is for bounds, assuming `offsetD[bid]` is the index into `knodesD`.
			// In our OpenMP simulation, `next_node_idx` is the index into `knodes`.
			if (next_node_idx < knodes_elem) {
				current_node_idx = next_node_idx;
			} else {
				// Handle error or break if index is out of bounds
				// For now, assume valid indices based on CUDA logic.
				// If it was out of bounds, it implies an issue with the tree structure or input.
				// The CUDA kernel would likely have undefined behavior or crash.
				// We'll assume valid indices for translation.
				current_node_idx = next_node_idx; // This might lead to issues if out of bounds
			}

			// The CUDA kernel's `if(thid == 0){ currKnodeD[bid] = offsetD[bid]; }`
			// implies that `currKnodeD[bid]` is updated for the next level by one thread.
			// In OpenMP, since each `bid` is an independent iteration, we can directly update.
			// The `current_node_idx` for the next iteration is determined by `next_node_idx`.
			// So, `currKnode[bid]` for the next level is `next_node_idx`.
			// We can update `currKnode[bid]` directly at the end of the inner loop.
		}
		// After the loop, `current_node_idx` holds the index of the leaf node.
		currKnode[bid] = current_node_idx; // Update currKnode for the final leaf node.

		// At this point, `currKnode[bid]` is the leaf node index.
		// Check each key in the leaf node to find the record.
		// The CUDA kernel used `thid` to check `knodesD[currKnodeD[bid]].keys[thid] == keysD[bid]`.
		// This means `thid` iterates through the keys of the leaf node.
		// We need to simulate this search for the `bid`-th query.
