		int search_key_final = keys[bid];
		int num_keys_in_leaf = knodes[leaf_node_idx].num_keys;

		for (int k = 0; k < num_keys_in_leaf; k++) {
			if (knodes[leaf_node_idx].keys[k] == search_key_final) {
				// Found the key, get the corresponding record value.
