	for(int bid = 0; bid < count; bid++){
		for(int i = 0; height > i; i++){
			// Find the correct child node
			int thid = 0;
			// The original CUDA code used thid+1 for keys access, implying keys[thid] and keys[thid+1] define a range.
			// This loop finds the first key that is greater than or equal to keysD[bid].
			// If keysD[bid] is smaller than the first key in the node, thid remains 0.
			// If keysD[bid] is larger than or equal to the last key, thid will become DEFAULT_ORDER.
			while(thid < DEFAULT_ORDER && keys[bid] >= knodes[currKnode[bid]].keys[thid]){
				thid++;
			}
			// The original CUDA code checked keysD[bid] >= knodesD[currKnodeD[bid]].keys[thid] && keysD[bid] < knodesD[currKnodeD[bid]].keys[thid+1]
			// This implies that `thid` should be the index such that keysD[bid] falls between keys[thid] and keys[thid+1].
			// The loop above finds the first `thid` where `keys[bid] < knodes[currKnode[bid]].keys[thid]`.
			// So, the correct index for the range check is `thid - 1`.
			int effective_thid = thid - 1;

			// Ensure effective_thid is valid and within bounds
			if (effective_thid < 0) {
				// If keys[bid] is smaller than the smallest key in the node, it should go to the first child.
				// The original CUDA code might have implicitly handled this or assumed keys are always found.
				// For safety, we can set effective_thid to 0 if keys[bid] is smaller than the first key.
				// However, the logic `keys[bid] >= knodes[currKnode[bid]].keys[thid]` means `thid` will be at least 1 if `keys[bid]` is >= the first key.
				// If `keys[bid]` is smaller than the first key, `thid` remains 0, and `effective_thid` becomes -1.
				// In a B-tree, if a key is smaller than the smallest key in an internal node, it belongs to the first child pointer.
				// So, if `effective_thid` is -1, it means the key is less than `knodes[currKnode[bid]].keys[0]`, and it should go to `knodes[currKnode[bid]].indices[0]`.
				effective_thid = 0; // Default to the first child if key is smaller than all keys in the node.
			} else if (effective_thid >= DEFAULT_ORDER) {
				// This case should ideally not happen if keys are properly ordered and the loop condition is correct.
				// If it does, it means keys[bid] is greater than or equal to the last key, and it should go to the last child pointer.
				effective_thid = DEFAULT_ORDER - 1; // Fallback to the last possible index.
			}


			if(knodes_elem > knodes[currKnode[bid]].indices[effective_thid]){
				offset[bid] = knodes[currKnode[bid]].indices[effective_thid];
			} else {
				// Handle cases where the index might be out of bounds or invalid
				// This might indicate an issue with the tree structure or input data
				// For now, we'll just break or set a default to avoid infinite loops or crashes
				// A more robust solution would involve error checking or specific handling
				break;
			}

			// set for next tree level
			currKnode[bid] = offset[bid];
		}

		// At this point, we have a candidate leaf node which may contain
		// the target record.  Check each key to hopefully find the record
		int thid = 0;
		// The original CUDA code checked `keysD[bid] == knodesD[currKnodeD[bid]].keys[thid]`
		// This implies a linear scan on the leaf node.
		while(thid < DEFAULT_ORDER && keys[bid] != knodes[currKnode[bid]].keys[thid]){
			thid++;
		}
		if (thid < DEFAULT_ORDER) { // Ensure key was found
			ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
		}
	}
}

