	time1 = get_time();

	//======================================================================================================================================================150
	//	KERNEL EXECUTION PARAMETERS
	//======================================================================================================================================================150

	// The number of threads per block and blocks per grid are implicitly handled by OpenMP's parallel for loop.
	// The loop is iterated 'count' times, and each iteration is a task for a thread.
	// The schedule(static) clause distributes iterations in chunks.

	printf("# of threads = %d\n", cores_arg);

