			ans,
			count);

	// Synchronization is implicit at the end of a parallel region.
	// If explicit synchronization is needed within the kernel, OpenMP barriers can be used.
	// For this kernel, the `findK` function's logic is now within the parallel region.

	time5 = get_time();

	//======================================================================================================================================================150
	//	DISPLAY TIMING
	//======================================================================================================================================================150

	printf("Time spent in different stages of CPU KERNEL:\n");

	printf("%15.12f s, %15.12f % : CPU: SET DEVICE / DRIVER INIT\n",	(float) (time1-time0) / 1000000, (float) (time1-time0) / (float) (time5-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: ALLOCATE CPU MEMORY\n", 		(float) (time2-time1) / 1000000, (float) (time2-time1) / (float) (time5-time0) * 100); // Placeholder, no explicit allocation here
	printf("%15.12f s, %15.12f % : CPU: COPY DATA TO CPU\n", 			(float) (time3-time2) / 1000000, (float) (time3-time2) / (float) (time5-time0) * 100); // Placeholder, data is already on CPU
	printf("%15.12f s, %15.12f % : CPU: PROCESSING\n", 				(float) (time4-time3) / 1000000, (float) (time4-time3) / (float) (time5-time0) * 100); // Placeholder for setup time
	printf("%15.12f s, %15.12f % : CPU: KERNEL\n", 					(float) (time5-time4) / 1000000, (float) (time5-time4) / (float) (time5-time0) * 100);
	printf("%15.12f s, %15.12f % : CPU: COPY DATA FROM CPU\n", 		(float) (time6-time5) / 1000000, (float) (time6-time5) / (float) (time5-time0) * 100); // Placeholder, no copy back needed

	printf("Total time:\n");
	printf("%.12f s\n", 												(float) (time5-time0) / 1000000);

