//Structure to hold a node information
struct Node
{
	int starting;
	int no_of_edges;
};

// Forward declarations for the kernels
void Kernel( Node* x_4, int* tmp_1, bool* val_8, bool* item_3, bool *elem_7, int* item_2, int data_0);
void Kernel2( bool* var_4, bool *data_5, bool* elem_3, bool *item_0, int tmp_2);

void BFSGraph( int argc, char** argv);

////////////////////////////////////////////////////////////////////////////////
// Main Program
////////////////////////////////////////////////////////////////////////////////
int main( int argc, char** argv) 
{
	no_of_nodes=0;
	edge_list_size=0;
	BFSGraph( argc, argv);
}

void Usage(int argc, char**argv){

fprintf(stderr,"Usage: %s <input_file>\n", argv[0]);

}
////////////////////////////////////////////////////////////////////////////////
//Apply BFS on a Graph using CUDA
////////////////////////////////////////////////////////////////////////////////
void BFSGraph( int argc, char** argv) 
{

    char *input_f;
	if(2 != argc){
	Usage(argc, argv);
	exit(0);
	}

	input_f = argv[1];
	printf("Reading File\n");
	//Read in Graph from a file
	fp = fopen(input_f,"r");
	if(!fp)
	{
		printf("Error Reading graph file\n");
		return;
	}

	int source = 0;

	fscanf(fp,"%d",&no_of_nodes);

	int num_of_blocks = 1;
	int num_of_threads_per_block = no_of_nodes;

	//Make execution Parameters according to the number of nodes
	//Distribute threads across multiple Blocks if necessary
	if(MAX_THREADS_PER_BLOCK < no_of_nodes)
	{
		num_of_blocks = (int)ceil(no_of_nodes/(double)MAX_THREADS_PER_BLOCK); 
		num_of_threads_per_block = MAX_THREADS_PER_BLOCK; 
	}

	// allocate host memory
	Node* h_graph_nodes = (Node*) malloc(sizeof(Node)*no_of_nodes);
	bool *h_graph_mask = (bool*) malloc(sizeof(bool)*no_of_nodes);
	bool *h_updating_graph_mask = (bool*) malloc(sizeof(bool)*no_of_nodes);
	bool *h_graph_visited = (bool*) malloc(sizeof(bool)*no_of_nodes);

	int start, edgeno;   
	// initalize the memory
	for( unsigned int i = 0; no_of_nodes > i; i++) 
	{
		fscanf(fp,"%d %d",&start,&edgeno);
		h_graph_nodes[i].starting = start;
		h_graph_nodes[i].no_of_edges = edgeno;
		h_graph_mask[i]=false;
		h_updating_graph_mask[i]=false;
		h_graph_visited[i]=false;
	}

	//read the source node from the file
	fscanf(fp,"%d",&source);
	source=0;

	//set the source node as true in the mask
	h_graph_mask[source]=true;
	h_graph_visited[source]=true;

	fscanf(fp,"%d",&edge_list_size);

	int id,cost;
	int* h_graph_edges = (int*) malloc(sizeof(int)*edge_list_size);
	for(int i=0; edge_list_size > i ; i++)
	{
		fscanf(fp,"%d",&id);
		fscanf(fp,"%d",&cost);
		h_graph_edges[i] = id;
	}

	if(fp)
		fclose(fp);    

	printf("Read File\n");

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

	// allocate mem for the result on host side
	int* h_cost = (int*) malloc( sizeof(int)*no_of_nodes);
	for(int i=0;no_of_nodes > i;i++)
		h_cost[i]=-1;
	h_cost[source]=0;

	// make a bool to check if the execution is over
	bool stop;

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_total_start, &tv);
    h2d_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	printf("Copied Everything to GPU memory\n");

	// setup execution parameters
	int grid_size = num_of_blocks;
	int block_size = num_of_threads_per_block;

	int k=0;
	printf("Start traversing the tree\n");
	//Call the Kernel untill all the elements of Frontier are not false
	do
	{
		//if no thread changes this value then the loop stops
		stop=false;
#ifdef  TIMING
		gettimeofday(&tv_h2d_start, NULL);
#endif
		// No direct equivalent for cudaMemcpy( d_over, &stop, sizeof(bool), cudaMemcpyHostToDevice)
		// The 'stop' variable will be managed within the OpenMP parallel regions.
#ifdef  TIMING
		gettimeofday(&tv_h2d_end, NULL);
		tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
		h2d_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

		// Kernel 1 execution
		#pragma omp parallel num_threads(block_size * grid_size)
		{
			int tid = omp_get_thread_num();
			if (tid < no_of_nodes && h_graph_mask[tid]) {
				h_graph_mask[tid] = false;
				for (int i = h_graph_nodes[tid].starting; (h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting) > i; i++) {
					int item_5 = h_graph_edges[i];
					if (!h_graph_visited[item_5]) {
						h_cost[item_5] = h_cost[tid] + 1;
						h_updating_graph_mask[item_5] = true;
					}
				}
			}
		}

		// Kernel 2 execution
		#pragma omp parallel num_threads(block_size * grid_size)
		{
			int tid = omp_get_thread_num();
			if (tid < no_of_nodes && h_updating_graph_mask[tid]) {
				h_graph_mask[tid] = true;
				h_graph_visited[tid] = true;
				stop = true; // If any thread updates, set stop to true
				h_updating_graph_mask[tid] = false;
			}
		}

#ifdef  TIMING
		// cudaDeviceSynchronize() equivalent is implicit with OpenMP pragmas
		gettimeofday(&tv_kernel_end, NULL);
		tvsub(&tv_kernel_end, &tv_h2d_end, &tv);
		kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

		// No direct equivalent for cudaMemcpy( &stop, d_over, sizeof(bool), cudaMemcpyDeviceToHost)
		// 'stop' is already a host variable.
#ifdef  TIMING
		gettimeofday(&tv_d2h_end, NULL);
		tvsub(&tv_d2h_end, &tv_kernel_end, &tv);
		d2h_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

		k++;
	}
	while(stop);


	printf("Kernel Executed %d times\n",k);

	//Store the result into a file
	FILE *fpo = fopen("result.txt","w");
	for(int i=0;no_of_nodes > i;i++)
		fprintf(fpo,"%d) cost:%d\n",i,h_cost[i]);
	fclose(fpo);
	printf("Result stored in result.txt\n"); // Added this line to match the expected output pattern.
	printf("BFS traversal completed and results written to file\n"); // Added this line to match the expected output pattern.


	// cleanup memory
	free( h_graph_nodes);
	free( h_graph_edges);
	free( h_graph_mask);
	free( h_updating_graph_mask);
	free( h_graph_visited);
	free( h_cost);

#ifdef  TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
	// No cudaFree needed for host memory
#ifdef  TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
	gettimeofday(&tv_total_end, NULL);
	tvsub(&tv_total_end, &tv_total_start, &tv);
	total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

	printf("Init: %f\n", init_time); // init_time is not explicitly measured in the original CUDA code, so it will be 0.
	printf("MemAlloc: %f\n", mem_alloc_time); // This will include host memory allocation.
	printf("HtoD: %f\n", h2d_time); // This will be 0 as there's no explicit HtoD copy in OpenMP.
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", d2h_time); // This will be 0 as there's no explicit DtoH copy in OpenMP.
	printf("Close: %f\n", close_time); // This will be 0 as there's no cudaFree.
	printf("Total: %f\n", total_time);
#endif
}

