template <typename T>
T* alloc(int N)
{
	return new T[N];
}

template <typename T>
void dealloc(T* array)
{
	delete[] array;
}

template <typename T>
void copy(T* dst, T* src, int N)
{
	#pragma omp parallel for
	for(int i = 0; i < N; ++i) {
		dst[i] = src[i];
	}
}

template <typename T>
void upload(T* dst, T* src, int N)
{
	copy(dst, src, N);
}

template <typename T>
void download(T* dst, T* src, int N)
{
	copy(dst, src, N);
}

