#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

void calculate_temp(int iteration,  //number of iteration
                               float *power,   //power input
                               float *temp_src,    //temperature input/output
                               float *temp_dst,    //temperature input/output
                               int grid_cols,  //Col of grid
                               int grid_rows,  //Row of grid
							   int border_cols,  // border offset
							   int border_rows,  // border offset
                               float Cap,      //Capacitance
                               float Rx,
                               float Ry,
                               float Rz,
                               float step,
                               float time_elapsed){

        float *temp_on_cuda = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
        float *power_on_cuda = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
        float *temp_t = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float)); // saving temparary temperature result

	float step_div_Cap;
	float Rx_1,Ry_1,Rz_1;

	step_div_Cap=step/Cap;

	Rx_1=1/Rx;
	Ry_1=1/Ry;
	Rz_1=1/Rz;

        // each block finally computes result for a small block
        // after N iterations.
        // it is the non-overlapping small blocks that cover
        // all the input data

        // calculate the small block size
	int small_block_rows = BLOCK_SIZE-iteration*2;//EXPAND_RATE
	int small_block_cols = BLOCK_SIZE-iteration*2;//EXPAND_RATE

        // calculate the boundary for the block according to
        // the boundary of its small block
        int blkY = small_block_rows*omp_get_team_num()-border_rows;
        int blkX = small_block_cols*omp_get_thread_num()-border_cols;
        int blkYmax = blkY+BLOCK_SIZE-1;
        int blkXmax = blkX+BLOCK_SIZE-1;

        // calculate the global thread coordination
	int yidx = blkY+omp_get_thread_num();
	int xidx = blkX+omp_get_thread_num();

        // load data if it is within the valid input range
	int loadYidx=yidx, loadXidx=xidx;
        int index = grid_cols*loadYidx+loadXidx;

	if(IN_RANGE(loadYidx, 0, grid_rows-1) && IN_RANGE(loadXidx, 0, grid_cols-1)){
            temp_on_cuda[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()] = temp_src[index];  // Load the temperature data from global memory to shared memory
            power_on_cuda[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()] = power[index];// Load the power data from global memory to shared memory
	}

        // effective range within this block that falls within
        // the valid range of the input data
        // used to rule out computation outside the boundary.
        int validYmin = (0 > blkY) ? -blkY : 0;
        int validYmax = (grid_rows-1 < blkYmax) ? BLOCK_SIZE-1-(blkYmax-grid_rows+1) : BLOCK_SIZE-1;
        int validXmin = (0 > blkX) ? -blkX : 0;
        int validXmax = (blkXmax > grid_cols-1) ? BLOCK_SIZE-1-(blkXmax-grid_cols+1) : BLOCK_SIZE-1;

        int N = omp_get_thread_num()-1;
        int S = omp_get_thread_num()+1;
        int W = omp_get_thread_num()-1;
        int E = omp_get_thread_num()+1;

        N = (validYmin > N) ? validYmin : N;
        S = (S > validYmax) ? validYmax : S;
        W = (W < validXmin) ? validXmin : W;
        E = (E > validXmax) ? validXmax : E;

        bool computed;
        for (int i=0; iteration > i ; i++){
            computed = false;
            if( IN_RANGE(omp_get_thread_num(), i+1, BLOCK_SIZE-i-2) &&
                  IN_RANGE(omp_get_thread_num(), i+1, BLOCK_SIZE-i-2) &&
                  IN_RANGE(omp_get_thread_num(), validXmin, validXmax) &&
                  IN_RANGE(omp_get_thread_num(), validYmin, validYmax) ) {
                  computed = true;
                  temp_t[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()] =   temp_on_cuda[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()] + step_div_Cap * (power_on_cuda[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()] +
	       	         (temp_on_cuda[S*BLOCK_SIZE + omp_get_thread_num()] + temp_on_cuda[N*BLOCK_SIZE + omp_get_thread_num()] - 2.0*temp_on_cuda[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()]) * Ry_1 +
		             (temp_on_cuda[omp_get_thread_num()*BLOCK_SIZE + E] + temp_on_cuda[omp_get_thread_num()*BLOCK_SIZE + W] - 2.0*temp_on_cuda[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()]) * Rx_1 +
		             (amb_temp - temp_on_cuda[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()]) * Rz_1);

            }
            #pragma omp barrier
            if(iteration-1 == i)
                break;
            if(computed)	 //Assign the computation range
                temp_on_cuda[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()]= temp_t[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()];
            #pragma omp barrier
          }

      // update the global memory
      // after the last iteration, only threads coordinated within the
      // small block perform the calculation and switch on ``computed''
      if (computed){
          temp_dst[index]= temp_t[omp_get_thread_num()*BLOCK_SIZE + omp_get_thread_num()];
      }
      free(temp_on_cuda);
      free(power_on_cuda);
      free(temp_t);
}

/*
   compute N time steps
*/

int compute_tran_temp(float *MatrixPower,float *MatrixTemp[2], int col, int row, \
		int total_iterations, int num_iterations, int blockCols, int blockRows, int borderCols, int borderRows)
{
	int src = 1, dst = 0;

	float grid_height = chip_height / row;
	float grid_width = chip_width / col;

	float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
	float Rx = grid_width / (2.0 * K_SI * t_chip * grid_height);
	float Ry = grid_height / (2.0 * K_SI * t_chip * grid_width);
	float Rz = t_chip / (K_SI * grid_height * grid_width);

	float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
	float step = PRECISION / max_slope;
	float t;
        float time_elapsed;
	time_elapsed=0.001;

	for (t = 0; t < total_iterations; t+=num_iterations) {
            int temp = src;
            src = dst;
            dst = temp;
            #pragma omp parallel num_threads(blockCols * blockRows)
            {
                #pragma omp for collapse(2)
                for(int by = 0; by < blockRows; ++by) {
                    for(int bx = 0; bx < blockCols; ++bx) {
                        calculate_temp(MIN(num_iterations, total_iterations-t), MatrixPower,MatrixTemp[src],MatrixTemp[dst],\
                            col,row,borderCols, borderRows, Cap,Rx,Ry,Rz,step,time_elapsed);
                    }
                }
            }
	}
        return dst;
}

