                float min_dist = FLT_MAX;

                // Find the nearest cluster center
                for (j = 0; j < nclusters; j++) {
                    float dist = 0.0f;
                    for (int k = 0; k < nfeatures; k++) {
                        float diff = feature[i][k] - new_centers[j][k];
                        dist += diff * diff;
                    }

                    if (dist < min_dist) {
                        min_dist = dist;
