            for (j = 0; j < i; j++) {
                peri_row[i][j] -= dia[i][j] * peri_row[j][j];
            }
        }

        // Perform computations for peri_col
        for (i = 0; i < BLOCK_SIZE; i++) {
            for (j = 0; j < i; j++) {
                peri_col[j][i] -= peri_col[j][j] * dia[j][i];
            }
            peri_col[j][i] /= dia[i][i];
        }

        // Write back modified peri_row
        for (i = 1; i < BLOCK_SIZE; i++) {
            array_offset = (offset + i) * matrix_dim + offset + (block_idx + 1) * BLOCK_SIZE;
            for (j = 0; j < BLOCK_SIZE; j++) {
                m[array_offset + j] = peri_row[i][j];
            }
        }

        // Write back modified peri_col
        for (i = 0; i < BLOCK_SIZE; i++) {
            array_offset = (offset + block_idx + 1) * BLOCK_SIZE * matrix_dim + offset + i * matrix_dim;
            for (j = 0; j < BLOCK_SIZE; j++) {
                m[array_offset + j] = peri_col[i][j];
            }
        }
    }
}

// OpenMP version of lud_internal
void lud_internal_omp(float *m, int matrix_dim, int offset) {
    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
    float peri_col[BLOCK_SIZE][BLOCK_SIZE];
    int i, j, array_offset;

    int num_blocks_per_dim = (matrix_dim - offset) / BLOCK_SIZE - 1;

    // Parallelize over the grid of internal blocks
    #pragma omp parallel for default(none) shared(m, matrix_dim, offset, BLOCK_SIZE, num_blocks_per_dim, peri_row, peri_col) private(i, j, array_offset)
    for (int block_y = 0; block_y < num_blocks_per_dim; ++block_y) {
        for (int block_x = 0; block_x < num_blocks_per_dim; ++block_x) {
            // Copy perimeter row elements to peri_row
            for (i = 0; i < BLOCK_SIZE; i++) {
                array_offset = (offset + i) * matrix_dim + offset + (block_x + 1) * BLOCK_SIZE;
                for (j = 0; j < BLOCK_SIZE; j++) {
                    peri_row[i][j] = m[array_offset + j];
                }
            }

            // Copy perimeter column elements to peri_col
            for (i = 0; i < BLOCK_SIZE; i++) {
                array_offset = (offset + (block_y + 1) * BLOCK_SIZE) * matrix_dim + offset + i * matrix_dim;
                for (j = 0; j < BLOCK_SIZE; j++) {
                    peri_col[i][j] = m[array_offset + j];
                }
            }

            // Compute the sum and update the internal block
            for (i = 0; i < BLOCK_SIZE; i++) {
                for (j = 0; j < BLOCK_SIZE; j++) {
                    float sum = 0;
                    for (int k = 0; k < BLOCK_SIZE; k++) {
                        sum += peri_col[i][k] * peri_row[k][j];
                    }
                    array_offset = (offset + (block_y + 1) * BLOCK_SIZE + i) * matrix_dim + offset + (block_x + 1) * BLOCK_SIZE + j;
                    m[array_offset] -= sum;
                }
            }
        }
    }
}

