#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

#include "define.h" // Assuming define.h exists for fp, EQUATIONS

// Forward declarations for functions called by solver
void embedded_fehlberg_7_8(fp timeinst, fp h, fp* initvalu, fp* finavalu, fp* error, fp* parameter, fp* com, fp* d_initvalu, fp* d_finavalu, fp* d_params, fp* d_com);
int solver(fp** y, fp* x, int xmax, fp* params, fp* com, fp* d_initvalu, fp* d_finavalu, fp* d_params, fp* d_com);

#define ATTEMPTS 12
#define MIN_SCALE_FACTOR 0.125
#define MAX_SCALE_FACTOR 4.0

//======================================================================================================================================================
//======================================================================================================================================================
//		SOLVER FUNCTION
//======================================================================================================================================================
//======================================================================================================================================================

int solver(	fp** y,
					fp* x,
					int xmax,
					fp* params,
					fp* com,

					fp* d_initvalu, // CUDA specific, ignored in OpenMP
					fp* d_finavalu,
					fp* d_params,
					fp* d_com) {

	//========================================================================================================================
	//	VARIABLES
	//========================================================================================================================

	// solver parameters
	fp err_exponent;
	int error;
	int outside;
	fp h;
	fp h_init;
	fp tolerance;
	int xmin;

	// memory
	fp scale_min;
	fp scale_fina;
	fp* err= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* scale= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* yy= (fp *) malloc(EQUATIONS* sizeof(fp));

	// counters
	int i, j, k;

	//========================================================================================================================
	//		INITIAL SETUP
	//========================================================================================================================

	// solver parameters
	err_exponent = 1.0 / 7.0;
	h_init = 1;
	h = h_init;
	xmin = 0;
	tolerance = 10 / (fp)(xmax-xmin);

	// save value for initial time instance
	x[0] = 0;

	//========================================================================================================================
	//		CHECKING
	//========================================================================================================================

	// Verify that the step size is positive and that the upper endpoint of integration is greater than the initial enpoint.               //
	if (xmin > xmax || 0.0 >= h){
		return -2;
	}

	// If the upper endpoint of the independent variable agrees with the initial value of the independent variable.  Set the value of the dependent variable and return success. //
	if (xmin == xmax){
		return 0;
	}

	// Insure that the step size h is not larger than the length of the integration interval.                                            //
	if (h > (xmax - xmin) ) {
		h = (fp)xmax - (fp)xmin;
	}

	//========================================================================================================================
	//		SOLVING
	//========================================================================================================================

	// The outer loop iterates through time steps.
	// We can parallelize this loop if each time step's computation is independent,
	// but the solver's adaptive step size nature makes direct parallelization tricky.
	// The original CUDA code parallelized across workloads, not within a single simulation's time steps.
	// For a single simulation instance (mode 0 in main.c), this loop should remain sequential.
	for(k=1; k<=xmax; k++) {											// start after initial value

		x[k] = k-1; // This seems to set the time instance to k-1, and the step 'h' adjusts it.
		h = h_init;

		//==========================================================================================
		//		REINITIALIZE VARIABLES
		//==========================================================================================

		scale_fina = 1.0;

		//==========================================================================================
		//		MAKE ATTEMPTS TO MINIMIZE ERROR
		//==========================================================================================

		// make attempts to minimize error
		for (j = 0; ATTEMPTS > j; j++) {

			//============================================================
			//		REINITIALIZE VARIABLES
			//============================================================

			error = 0;
			outside = 0;
			scale_min = MAX_SCALE_FACTOR;

			//============================================================
			//		EVALUATE ALL EQUATIONS
			//============================================================

			// Call the embedded_fehlberg_7_8 function.
			// The CUDA-specific arguments (d_initvalu, etc.) are passed as NULL
			// as they are not used in the OpenMP CPU version.
			embedded_fehlberg_7_8(	x[k],
														h,
														y[k-1],
														y[k],
														err,
														params,
														com,
														NULL, // d_initvalu ignored
														NULL, // d_finavalu ignored
														NULL, // d_params ignored
														NULL  // d_com ignored
														);

			//============================================================
			//		IF THERE WAS NO ERROR FOR ANY OF EQUATIONS, SET SCALE AND LEAVE THE LOOP
			//============================================================

			// Check if any error occurred. If err[i] > 0, it indicates an error.
			// This check seems reversed in the original code. Assuming err[i] > 0 means an error occurred.
			// If no error, break the inner loop.
			for(i=0; i<EQUATIONS; i++){
				if(err[i] > 0){ // Assuming err[i] > 0 indicates an issue that needs re-evaluation
					error = 1;
					break;
				}
			}
			if (error != 1) {
				scale_fina = MAX_SCALE_FACTOR;
				break;
			}

			//============================================================
			//		FIGURE OUT SCALE AS THE MINIMUM OF COMPONENT SCALES
			//============================================================

			for(i=0; i<EQUATIONS; i++){
				if(y[k-1][i] == 0.0){
					yy[i] = tolerance;
				}
				else{
					yy[i] = fabs(y[k-1][i]);
				}
				// Calculate scale factor for each equation
				scale[i] = 0.8 * pow( tolerance * yy[i] / err[i] , err_exponent );
				if(scale[i]<scale_min){
					scale_min = scale[i];
				}
			}
			// Determine the overall scale factor, constrained between MIN_SCALE_FACTOR and MAX_SCALE_FACTOR
			scale_fina = fmin( fmax(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

			//============================================================
			//		IF WITHIN TOLERANCE, FINISH ATTEMPTS...
			//============================================================

			// Check if the error is within tolerance for all equations.
			// If error[i] <= tolerance * yy[i], it's within tolerance.
			// 'outside' flag indicates if any equation is outside tolerance.
			for(i=0; i<EQUATIONS; i++){
				if ( err[i] > ( tolerance * yy[i] ) ){
					outside = 1;
					break; // Exit early if one equation is outside tolerance
				}
			}
			if (outside == 0){
				break; // All equations are within tolerance, exit the attempts loop
			}

			//============================================================
			//		...OTHERWISE, ADJUST STEP FOR NEXT ATTEMPT
			//============================================================

			// scale next step in a default way
			h = h * scale_fina;

			// limit step to 0.9, because when it gets close to 1, it no longer makes sense, as 1 is already the next time instance (added to original algorithm)
			if (0.9 <= h) {
				h = 0.9;
			}

			// if instance+step exceeds range limit, limit to that range
			if ( x[k] + h > (fp)xmax ){
				h = (fp)xmax - x[k];
			}

			// if getting closer to range limit, decrease step
			else if ( x[k] + h + 0.5 * h > (fp)xmax ){
				h = 0.5 * h;
			}

		}

		//==========================================================================================
		//		SAVE TIME INSTANCE THAT SOLVER ENDED UP USING
		//==========================================================================================

		x[k] = x[k] + h;

		//==========================================================================================
		//		IF MAXIMUM NUMBER OF ATTEMPTS REACHED AND CANNOT GIVE SOLUTION, EXIT PROGRAM WITH ERROR
		//==========================================================================================

		if ( ATTEMPTS <= j ) {
			// Free allocated memory before returning error
			free(err);
			free(scale);
			free(yy);
			return -1;
		}

	}

	//========================================================================================================================
	//		FREE MEMORY
	//========================================================================================================================

	free(err);
	free(scale);
	free(yy);

	//========================================================================================================================
	//		FINAL RETURN
	//========================================================================================================================

	return 0;

}

