/**
* Kernel
* Executed on CPU using OpenMP
* Calculates the Euclidean distance from each record in the database to the target position
*/
void euclid_omp(LatLong *locations, float *distances, int numRecords, float lat, float lng)
{
    #pragma omp parallel for
    for (int globalId = 0; globalId < numRecords; ++globalId) {
        LatLong current_location = locations[globalId];
        distances[globalId] = (float)sqrt((lat - current_location.lat) * (lat - current_location.lat) + (lng - current_location.lng) * (lng - current_location.lng));
    }
}

