void needle_kernel_1(  int* referrence,
			  int* matrix_cuda,
			  int cols,
			  int penalty,
			  int diag_idx, // Corresponds to 'i' in the CUDA kernel launch loop
			  int block_width)
{
  // In OpenMP, we simulate CUDA blocks and threads.
  // Each thread in the parallel region will act as a CUDA block.
  // The thread ID within the team will be the thread ID within the block.
  int bx = omp_get_thread_num(); // Thread ID within the team (simulates blockIdx.x)
  int tx = omp_get_thread_num(); // Thread ID within the block (simulates threadIdx.x)

  // Calculate indices based on the diagonal and block structure
  int b_index_x = bx;
  int b_index_y = diag_idx - 1 - bx;

  // Calculate the starting index for the current block in the global matrix
  int base_index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

  // Global memory indices for the current thread
  int index   = base_index + tx + ( cols + 1 );
  int index_n   = base_index + tx + ( 1 );
  int index_w   = base_index + ( cols );
  int index_nw =  base_index;

  // OpenMP does not have direct equivalent of __shared__ memory.
  // We use thread-private arrays to mimic the behavior.
  // This is a simplification; a more optimized OpenMP version might use different data structures or loop transformations.
  int temp[BLOCK_SIZE+1][BLOCK_SIZE+1];
  int ref[BLOCK_SIZE][BLOCK_SIZE];

   // Load boundary values into temp array
   if (tx == 0)
		  temp[tx][0] = matrix_cuda[index_nw]; // Top-left corner of the block

  // Load reference values into ref array
  for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
  ref[ty][tx] = referrence[index + cols * ty];

  // Synchronize threads within the team to ensure ref and initial temp values are loaded
  #pragma omp barrier

  // Load other boundary values
  temp[tx + 1][0] = matrix_cuda[index_w + cols * tx]; // Left boundary
  temp[0][tx + 1] = matrix_cuda[index_n];             // Top boundary

  // Synchronize threads within the team
  #pragma omp barrier

  // Main computation loop for the block
  for( int m = 0 ; m < BLOCK_SIZE ; m++){
	  if ( tx <= m ){ // Only process elements within the current thread's responsibility
		  int t_index_x =  tx + 1;
		  int t_index_y =  m - tx + 1;

          temp[t_index_y][t_index_x] = maximum( temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
		                                        temp[t_index_y][t_index_x-1]  - penalty,
												temp[t_index_y-1][t_index_x]  - penalty);
	  }
	  // Synchronize threads within the team to ensure dependencies are met for the next iteration
	  #pragma omp barrier
  }

  // Second phase of computation for the block (lower triangle)
  for( int m = BLOCK_SIZE - 2 ; m >=0 ; m--){
	  if ( tx <= m){ // Only process elements within the current thread's responsibility
		  int t_index_x =  tx + BLOCK_SIZE - m ;
		  int t_index_y =  BLOCK_SIZE - tx;

          temp[t_index_y][t_index_x] = maximum( temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
		                                        temp[t_index_y][t_index_x-1]  - penalty,
												temp[t_index_y-1][t_index_x]  - penalty);
	  }
	  // Synchronize threads within the team
	  #pragma omp barrier
  }

  // Write results back to global memory
  for ( int ty = 0 ; ty < BLOCK_SIZE ; ty++)
  matrix_cuda[index + ty * cols] = temp[ty+1][tx+1];
}


