#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

void dynproc_kernel(
                int iteration, 
                int *gpuWall,
                int *gpuSrc,
                int *gpuResults,
                int cols, 
                int rows,
                int startStep,
                int border)
{
        int tid = omp_get_thread_num();
        int block_id = omp_get_team_num();

        int small_block_cols = BLOCK_SIZE-iteration*HALO*2;
        int blkX = small_block_cols*block_id-border;
        int blkXmax = blkX+BLOCK_SIZE-1;
        int xidx = blkX+tid;
        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;
        int W = tid-1;
        int E = tid+1;

        W = (W < validXmin) ? validXmin : W;
        E = (E > validXmax) ? validXmax : E;

        bool isValid = IN_RANGE(tid, validXmin, validXmax);
        bool computed;

        if(IN_RANGE(xidx, 0, cols-1)){
            gpuSrc[xidx] = gpuWall[xidx];
        }
        #pragma omp barrier

        for (int i=0; i<iteration ; i++){ 
            computed = false;
            if( IN_RANGE(tid, i+1, BLOCK_SIZE-i-2) &&  \
                  isValid){
                  computed = true;
                  int left = gpuSrc[W];
                  int up = gpuSrc[tid];
                  int right = gpuSrc[E];
                  int shortest = MIN(left, up);
                  shortest = MIN(shortest, right);
                  int index = cols*(startStep+i)+xidx;
                  gpuResults[tid] = shortest + gpuWall[index];

            }
            #pragma omp barrier
            if(i==iteration-1)
                break;
            if(computed)
                gpuSrc[tid]= gpuResults[tid];
	    #pragma omp barrier
      }

      if (computed){
          gpuResults[xidx]=gpuResults[tid];		
      }
}

/*
   compute N time steps
*/
int calc_path(int *gpuWall, int *gpuResult[2], int rows, int cols, \
	 int pyramid_height, int blockCols, int borderCols)
{

        int src = 1, dst = 0;
	for (int t = 0; t < rows-1; t+=pyramid_height) {
            int temp = src;
            src = dst;
            dst = temp;

            int current_iteration = MIN(pyramid_height, rows-t-1);
            int num_blocks = blockCols;
            int threads_per_block = BLOCK_SIZE;

            #pragma omp parallel num_teams(num_blocks) thread_limit(threads_per_block)
            {
                #pragma omp teams distribute parallel for 
                for (int bx = 0; bx < num_blocks; ++bx) {
                    dynproc_kernel(
                        current_iteration, 
                        gpuWall, gpuResult[src], gpuResult[dst],
                        cols,rows, t, borderCols);
                }
            }
	}
        return dst;
}

