#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

void dynproc_kernel(
                int iteration, 
                int *gpuWall,
                int *gpuSrc,
                int *gpuResults,
                int cols, 
                int rows,
                int startStep,
                int border)
{
        int small_block_cols = BLOCK_SIZE-iteration*HALO*2;
        int blkX = small_block_cols*omp_get_num_threads()-border;
        int blkXmax = blkX+BLOCK_SIZE-1;
        int xidx = blkX+omp_get_thread_num();
        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;
        int W = omp_get_thread_num()-1;
        int E = omp_get_thread_num()+1;

        W = (validXmin > W) ? validXmin : W;
        E = (E > validXmax) ? validXmax : E;

        bool isValid = IN_RANGE(omp_get_thread_num(), validXmin, validXmax);

        int *prev = (int*)calloc(BLOCK_SIZE, sizeof(int));
        int *result = (int*)calloc(BLOCK_SIZE, sizeof(int));

	if(IN_RANGE(xidx, 0, cols-1)){
            prev[omp_get_thread_num()] = gpuSrc[xidx];
	}
        #pragma omp barrier
        bool computed;
        for (int i=0; iteration > i ; i++){ 
            computed = false;
            if( IN_RANGE(omp_get_thread_num(), i+1, BLOCK_SIZE-i-2) &&  \
                  isValid){
                  computed = true;
                  int left = prev[W];
                  int up = prev[omp_get_thread_num()];
                  int right = prev[E];
                  int shortest = MIN(left, up);
                  shortest = MIN(shortest, right);
                  int index = cols*(startStep+i)+xidx;
                  result[omp_get_thread_num()] = shortest + gpuWall[index];

            }
            #pragma omp barrier
            if(iteration-1 == i)
                break;
            if(computed)	 
                prev[omp_get_thread_num()]= result[omp_get_thread_num()];
	    #pragma omp barrier 
      }

      if (computed){
          gpuResults[xidx]=result[omp_get_thread_num()];		
      }
      free(prev);
      free(result);
}

/*
   compute N time steps
*/
int calc_path(int *gpuWall, int *gpuResult[2], int rows, int cols, \
	 int pyramid_height, int blockCols, int borderCols)
{

        int src = 1, dst = 0;
	for (int t = 0; rows-1 > t; t+=pyramid_height) {
            int temp = src;
            src = dst;
            dst = temp;
            #pragma omp parallel
            {
                dynproc_kernel(
                    MIN(pyramid_height, rows-t-1), 
                    gpuWall, gpuResult[src], gpuResult[dst],
                    cols,rows, t, borderCols);
            }
	}
        return dst;
}

