	// cudaEventRecord(stop,0);
	// cudaEventSynchronize(stop);
	// cudaEventElapsedTime(&tmp_t, start, stop);
	// *kernel_t += (double) tmp_t;
    *kernel_t += (omp_get_wtime() - start_time) * 1000.0;

	// cudaEventRecord(start,0);
    start_time = omp_get_wtime();
#endif

