	for(int i=0; i < num; i++)
	{
		if( is_center[i] )
		{
			float low = z;
		    for( int j = 0; j < num; j++ )
			{
				low += work_mem_h[ j*stride + center_table[i] ];
			}

		    gl_lower[center_table[i]] = low;

		    if ( low > 0 )
			{
				++number_of_centers_to_close;
				work_mem_h[i*stride+K] -= low;
		    }
		}
		gl_cost_of_opening_x += work_mem_h[i*stride+K];
	}

	//if opening a center at x saves cost (i.e. cost is negative) do so; otherwise, do nothing
	if ( gl_cost_of_opening_x < 0 )
	{
		for(int i = 0; i < num; i++)
		{
			bool close_center = gl_lower[center_table[points->p[i].assign]] > 0 ;
			if ( switch_membership[i] || close_center )
			{
				// points->p[i].cost = dist(points->p[i], points->p[x], dim) * points->p[i].weight;
                float distance = 0.0;
                for(int d_idx = 0; d_idx < dim; ++d_idx) {
                    distance += (points->p[i].coord[d_idx] - points->p[x].coord[d_idx]) * (points->p[i].coord[d_idx] - points->p[x].coord[d_idx]);
                }
                points->p[i].cost = distance * points->p[i].weight;
				points->p[i].assign = x;
			}
		}

		for(int i = 0; i < num; i++)
		{
			if( is_center[i] && gl_lower[center_table[i]] > 0 )
			{
				is_center[i] = false;
			}
		}

		if( x >= 0 && x < num)
		{
			is_center[x] = true;
		}
		*numcenters = *numcenters + 1 - number_of_centers_to_close;
	}
	else
	{
		gl_cost_of_opening_x = 0;
	}

	//=======================================
	// DEALLOCATE HOST MEMORY
	//=======================================
	free(work_mem_h);


#ifdef CUDATIME
	// cudaEventRecord(stop,0);
	// cudaEventSynchronize(stop);
	// cudaEventElapsedTime(&tmp_t, start, stop);
	// *serial_t += (double) tmp_t;
    *serial_t += (omp_get_wtime() - start_time) * 1000.0;

	// cudaEventRecord(start,0);
    start_time = omp_get_wtime();
#endif

	//=======================================
	// DEALLOCATE GPU MEMORY
	//=======================================
	// CUDA_SAFE_CALL( cudaFree(work_mem_d) );
    free(work_mem_d);


#ifdef CUDATIME
	// cudaEventRecord(stop,0);
	// cudaEventSynchronize(stop);
	// cudaEventElapsedTime(&tmp_t, start, stop);
	// *free_t += (double) tmp_t;
    *free_t += (omp_get_wtime() - start_time) * 1000.0;
#endif
	iter++;
	return -gl_cost_of_opening_x;
}

