    free(work_mem_d);


#ifdef CUDATIME
	// cudaEventRecord(stop,0);
	// cudaEventSynchronize(stop);
	// cudaEventElapsedTime(&tmp_t, start, stop);
	// *free_t += (double) tmp_t;
    *free_t += (omp_get_wtime() - start_time) * 1000.0;
#endif
	iter++;
	return -gl_cost_of_opening_x;
}

